import{_ as a,o as t,c as s,a2 as n}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse('{"title":"Claude Code","description":"","frontmatter":{"title":"Claude Code","status":"complete"},"headers":[],"relativePath":"research/agents/claude-code/index.md","filePath":"research/agents/claude-code/index.md"}'),o={name:"research/agents/claude-code/index.md"};function i(l,e,r,d,c,p){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="claude-code" tabindex="-1">Claude Code <a class="header-anchor" href="#claude-code" aria-label="Permalink to &quot;Claude Code&quot;">​</a></h1><blockquote><p>Anthropic&#39;s first-party agentic coding assistant — a terminal-native CLI agent built in TypeScript with an Ink-based TUI.</p></blockquote><h2 id="what-it-is" tabindex="-1">What It Is <a class="header-anchor" href="#what-it-is" aria-label="Permalink to &quot;What It Is&quot;">​</a></h2><p>Claude Code is Anthropic&#39;s official CLI coding agent. It lives in the terminal, understands entire codebases, and executes multi-step coding tasks autonomously through natural language. Unlike inline autocomplete tools, Claude Code operates as a full agentic system: it reads files, runs commands, edits code, searches the web, and verifies its own work — all within a multi-turn conversation loop.</p><ul><li><strong>First released</strong>: February 2025 (research preview), GA mid-2025</li><li><strong>Distribution</strong>: npm package (<code>@anthropic-ai/claude-code</code>), native installers, Homebrew, WinGet</li><li><strong>Platforms</strong>: macOS, Linux, Windows (WSL), plus VS Code / JetBrains extensions, Desktop app, Web UI</li><li><strong>License</strong>: Closed-source (the GitHub repo at <code>anthropics/claude-code</code> hosts the npm package, plugins, and issue tracker — not the full source)</li><li><strong>Runtime</strong>: Node.js 18+, TypeScript, Ink (React for CLI)</li><li><strong>Models</strong>: Claude Sonnet, Opus, and Haiku (user-selectable per session)</li></ul><h2 id="terminal-bench-2-0-rankings" tabindex="-1">Terminal-Bench 2.0 Rankings <a class="header-anchor" href="#terminal-bench-2-0-rankings" aria-label="Permalink to &quot;Terminal-Bench 2.0 Rankings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rank</th><th>Agent + Model</th><th>Score</th></tr></thead><tbody><tr><td>#39</td><td>Claude Code (Claude Opus 4.6)</td><td>58.0%</td></tr><tr><td>#48</td><td>Claude Code (Claude Opus 4.5)</td><td>52.1%</td></tr><tr><td>#69</td><td>Claude Code (Claude Sonnet 4.5)</td><td>40.1%</td></tr></tbody></table><h2 id="key-capabilities" tabindex="-1">Key Capabilities <a class="header-anchor" href="#key-capabilities" aria-label="Permalink to &quot;Key Capabilities&quot;">​</a></h2><ul><li><strong>Agentic coding loop</strong>: Gather context → take action → verify results, repeated until task complete</li><li><strong>Full codebase awareness</strong>: Reads across files, understands project structure, makes coordinated multi-file edits</li><li><strong>Permission model</strong>: Graduated trust levels (default → auto-accept edits → plan mode → bypass) with per-tool allow/ask/deny rules</li><li><strong>CLAUDE.md project memory</strong>: Persistent instructions loaded every session, plus auto-memory for learned patterns</li><li><strong>Sub-agent spawning</strong>: Built-in Explore, Plan, and general-purpose sub-agents; custom sub-agents via <code>.claude/agents/</code></li><li><strong>MCP server support</strong>: Connect to external tools (GitHub, Sentry, databases, Figma) via Model Context Protocol</li><li><strong>Context compaction</strong>: Automatic compaction when approaching limits, plus manual <code>/compact</code> command</li><li><strong>Git integration</strong>: Branch-aware sessions, worktree support for parallel sessions, PR creation</li><li><strong>Multi-surface</strong>: Same engine across terminal, VS Code, JetBrains, Desktop app, Web, Slack, GitHub Actions</li></ul><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a Glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a Glance&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              Ink TUI (React for CLI)         │</span></span>
<span class="line"><span>│  ┌────────┐ ┌──────────┐ ┌───────────────┐  │</span></span>
<span class="line"><span>│  │ Input  │ │ Renderer │ │ Permission UI │  │</span></span>
<span class="line"><span>│  └────────┘ └──────────┘ └───────────────┘  │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│            Agentic Harness                   │</span></span>
<span class="line"><span>│  ┌─────────────┐  ┌────────────────────┐    │</span></span>
<span class="line"><span>│  │ Agent Loop   │  │ Context Manager   │    │</span></span>
<span class="line"><span>│  │ (multi-turn) │  │ (compaction,      │    │</span></span>
<span class="line"><span>│  │              │  │  CLAUDE.md, etc.) │    │</span></span>
<span class="line"><span>│  └─────────────┘  └────────────────────┘    │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│              Tool System                     │</span></span>
<span class="line"><span>│  Read │ Edit │ Bash │ Grep │ Glob │ Web*   │</span></span>
<span class="line"><span>│  Agent │ Write │ WebFetch │ MCP tools      │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│         Permission / Safety Layer            │</span></span>
<span class="line"><span>│  allow/ask/deny rules │ sandboxing │ hooks  │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│         Claude API (Sonnet/Opus/Haiku)       │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="research-files" tabindex="-1">Research Files <a class="header-anchor" href="#research-files" aria-label="Permalink to &quot;Research Files&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Contents</th></tr></thead><tbody><tr><td><a href="./architecture.html">architecture.md</a></td><td>TypeScript + Ink stack, tool system, permission model, session management</td></tr><tr><td><a href="./agentic-loop.html">agentic-loop.md</a></td><td>The gather → act → verify loop, model selection, tool chaining</td></tr><tr><td><a href="./tool-system.html">tool-system.md</a></td><td>All known tools, permission levels, MCP integration</td></tr><tr><td><a href="./context-management.html">context-management.md</a></td><td>/compact, auto-compaction, CLAUDE.md, auto-memory, sub-agents for context isolation</td></tr><tr><td><a href="./unique-patterns.html">unique-patterns.md</a></td><td>Key differentiators vs. other coding agents</td></tr><tr><td><a href="./benchmarks.html">benchmarks.md</a></td><td>Terminal-Bench 2.0, SWE-bench scores, model comparisons</td></tr><tr><td><a href="./references.html">references.md</a></td><td>Official docs, blog posts, public analyses</td></tr></tbody></table><h2 id="key-takeaways-for-agent-builders" tabindex="-1">Key Takeaways for Agent Builders <a class="header-anchor" href="#key-takeaways-for-agent-builders" aria-label="Permalink to &quot;Key Takeaways for Agent Builders&quot;">​</a></h2><ol><li><strong>Permission model as a first-class feature</strong>: Claude Code&#39;s graduated trust system (default → acceptEdits → plan → bypassPermissions) is the most sophisticated permission model in any coding agent. It balances autonomy with safety.</li><li><strong>Context is the bottleneck</strong>: The entire best-practices guide centers around one constraint — the context window fills up fast. Auto-compaction, <code>/compact</code>, sub-agents, and skills all exist to manage this.</li><li><strong>CLAUDE.md as project memory</strong>: A simple but powerful pattern — a markdown file loaded every session that gives the agent persistent instructions. Other agents could adopt this.</li><li><strong>Sub-agent architecture</strong>: Spawning child agents with separate context windows for exploration keeps the main conversation clean. The Explore sub-agent uses Haiku for speed.</li><li><strong>Hooks system</strong>: Deterministic shell scripts at lifecycle points (PreToolUse, PostToolUse, etc.) complement the advisory CLAUDE.md with hard enforcement.</li><li><strong>Skills as on-demand knowledge</strong>: Unlike CLAUDE.md (always loaded), skills load only when relevant, reducing context waste.</li></ol>`,15)])])}const m=a(o,[["render",i]]);export{h as __pageData,m as default};
